import{_ as t,o as a,c as i,a2 as n}from"./chunks/framework.BsCfuO2w.js";const c=JSON.parse('{"title":"必读基础","description":"","frontmatter":{},"headers":[],"relativePath":"guide/basics.md","filePath":"guide/basics.md","lastUpdated":1782829900000}'),e={name:"guide/basics.md"};function p(h,s,d,l,r,o){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="必读基础" tabindex="-1">必读基础 <a class="header-anchor" href="#必读基础" aria-label="Permalink to &quot;必读基础&quot;">​</a></h1><p>如果你从没接触过 Web 后端 / HTTP / 服务器，先读这一页。</p><p>只要 5 分钟。</p><h2 id="什么是-http" tabindex="-1">什么是 HTTP？ <a class="header-anchor" href="#什么是-http" aria-label="Permalink to &quot;什么是 HTTP？&quot;">​</a></h2><p>HTTP 是一种「<strong>客户端问 → 服务器答</strong>」的协议。</p><ul><li><strong>客户端</strong>：浏览器、App</li><li><strong>服务器</strong>：跑在 ESP32 上的 nova-server</li></ul><p>每次交互有两步：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端  ──── &quot;GET /hello&quot; ────►  服务器</span></span>
<span class="line"><span>客户端  ◄──── &quot;Hello, World!&quot; ──  服务器</span></span></code></pre></div><h2 id="什么是-url" tabindex="-1">什么是 URL？ <a class="header-anchor" href="#什么是-url" aria-label="Permalink to &quot;什么是 URL？&quot;">​</a></h2><p>URL 就是网址，比如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.1.42/hello?name=World</span></span>
<span class="line"><span>│      │             │      │</span></span>
<span class="line"><span>│      │             │      └─ 查询字符串（可选，见下）</span></span>
<span class="line"><span>│      │             └─────── 路径</span></span>
<span class="line"><span>│      └───────────────────  IP 地址</span></span>
<span class="line"><span>└────────────────────────── 协议</span></span></code></pre></div><p><strong>路径</strong>告诉服务器要访问哪个接口。</p><table tabindex="0"><thead><tr><th>URL</th><th>路径</th></tr></thead><tbody><tr><td><code>http://esp32/</code></td><td><code>/</code></td></tr><tr><td><code>http://esp32/about</code></td><td><code>/about</code></td></tr><tr><td><code>http://esp32/users/42</code></td><td><code>/users/42</code></td></tr></tbody></table><h2 id="什么是「端口」" tabindex="-1">什么是「端口」？ <a class="header-anchor" href="#什么是「端口」" aria-label="Permalink to &quot;什么是「端口」？&quot;">​</a></h2><p>一台机器可以跑多个服务（HTTP、SSH、MQTT…）。<strong>端口</strong>用来区分它们。</p><table tabindex="0"><thead><tr><th>端口</th><th>通常是</th></tr></thead><tbody><tr><td>80</td><td>HTTP（浏览器默认）</td></tr><tr><td>443</td><td>HTTPS</td></tr><tr><td>22</td><td>SSH</td></tr><tr><td>5000</td><td>nova-server PC 开发默认（用 <code>NovaServer(port=5000)</code> 显式指定）</td></tr></tbody></table><p>访问 <code>http://esp32-ip/</code> 实际是访问 <code>http://esp32-ip:80/</code>（80 是 HTTP 默认）。<code>app.run()</code> 不传 port 时默认就监听 80。</p><p>如果你用其他端口，要加 <code>:端口号</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://esp32-ip:5000/    # 5000 端口（PC 开发常见）</span></span></code></pre></div><h2 id="什么是-http-方法" tabindex="-1">什么是 HTTP 方法？ <a class="header-anchor" href="#什么是-http-方法" aria-label="Permalink to &quot;什么是 HTTP 方法？&quot;">​</a></h2><p>最常见的是 <code>GET</code> 和 <code>POST</code>。</p><table tabindex="0"><thead><tr><th>方法</th><th>用途</th><th>类比</th></tr></thead><tbody><tr><td><strong>GET</strong></td><td>读数据</td><td>你在网页上看文章</td></tr><tr><td><strong>POST</strong></td><td>发数据</td><td>你提交表单</td></tr></tbody></table><p>浏览器地址栏访问网页 = <strong>GET</strong> 请求。</p><h2 id="什么是「接口」" tabindex="-1">什么是「接口」？ <a class="header-anchor" href="#什么是「接口」" aria-label="Permalink to &quot;什么是「接口」？&quot;">​</a></h2><p>接口 = 一个 URL 地址 + 处理函数。</p><p>nova-server 里写一个接口：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@app.get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/hello&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 路径</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> hello</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(request):        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 处理函数</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Hello!&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 返回内容</span></span></code></pre></div><p>只要这样写，访问 <code>http://esp32-ip/hello</code> 就会返回 <code>Hello!</code>。</p><h2 id="什么是-json" tabindex="-1">什么是 JSON？ <a class="header-anchor" href="#什么是-json" aria-label="Permalink to &quot;什么是 JSON？&quot;">​</a></h2><p>JSON 是一种数据格式。长得像 Python 的 dict / list：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Alice&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;age&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hobbies&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;reading&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;coding&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>nova-server 里你返回 dict，<strong>自动</strong>转 JSON：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@app.get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/api/user&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(request):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;name&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Alice&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;age&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ↑ 这个 dict 自动变 JSON</span></span></code></pre></div><p>客户端拿到的是：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Alice&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;age&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="什么是-async-await" tabindex="-1">什么是 async / await？ <a class="header-anchor" href="#什么是-async-await" aria-label="Permalink to &quot;什么是 async / await？&quot;">​</a></h2><p>nova-server 的 handler 必须是 <code>async def</code>，函数里可能用 <code>await</code>。</p><p>简单理解：</p><ul><li><code>async def</code> = 「这个函数可以<strong>等待</strong>别的事情」</li><li><code>await xxx()</code> = 「先停一下，等 xxx 完成再继续」</li><li>等待时<strong>不卡</strong>其他客户端</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@app.get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/slow&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">async</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> slow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(request):</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> asyncio.sleep(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等 1 秒（不卡 server）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;done&#39;</span></span></code></pre></div><p>为什么需要？因为 ESP32 单核，没线程。普通 <code>time.sleep(1)</code> 会让整个 server 卡 1 秒。</p><h2 id="什么是-ip-地址" tabindex="-1">什么是 IP 地址？ <a class="header-anchor" href="#什么是-ip-地址" aria-label="Permalink to &quot;什么是 IP 地址？&quot;">​</a></h2><p>IP 是设备在网络里的地址。</p><table tabindex="0"><thead><tr><th>设备</th><th>IP 例子</th></tr></thead><tbody><tr><td>你的电脑</td><td>192.168.1.10</td></tr><tr><td>ESP32</td><td>192.168.1.42</td></tr><tr><td>路由器</td><td>192.168.1.1</td></tr></tbody></table><p>同一 WiFi 下的设备可以互相访问。手机连 ESP32 的热点也能访问。</p><h2 id="什么是-repl" tabindex="-1">什么是 REPL？ <a class="header-anchor" href="#什么是-repl" aria-label="Permalink to &quot;什么是 REPL？&quot;">​</a></h2><p>REPL = <strong>R</strong>ead-<strong>E</strong>val-<strong>P</strong>rint <strong>L</strong>oop。就是你能在电脑上打字让 ESP32 立刻执行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt;&gt;&gt; 1 + 2</span></span>
<span class="line"><span>3</span></span>
<span class="line"><span>&gt;&gt;&gt; import network</span></span>
<span class="line"><span>&gt;&gt;&gt; w = network.WLAN(network.STA_IF)</span></span>
<span class="line"><span>&gt;&gt;&gt; w.isconnected()</span></span>
<span class="line"><span>True</span></span></code></pre></div><p>非常适合调试。</p><h2 id="名词对照表" tabindex="-1">名词对照表 <a class="header-anchor" href="#名词对照表" aria-label="Permalink to &quot;名词对照表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名词</th><th>是什么</th></tr></thead><tbody><tr><td>HTTP</td><td>客户端-服务器通信协议</td></tr><tr><td>URL</td><td>网址</td></tr><tr><td>路径</td><td><code>/about</code> 这种</td></tr><tr><td>端口</td><td>一个机器上的多个服务用端口区分</td></tr><tr><td>GET</td><td>读数据</td></tr><tr><td>POST</td><td>发数据</td></tr><tr><td>接口 / 路由</td><td>URL + 处理函数</td></tr><tr><td>JSON</td><td>数据格式（像 Python dict）</td></tr><tr><td>async / await</td><td>Python 异步语法</td></tr><tr><td>IP 地址</td><td>设备在网络里的地址</td></tr><tr><td>REPL</td><td>交互式命令行</td></tr><tr><td>MicroPython</td><td>跑在微控制器上的 Python</td></tr><tr><td>NovaMP</td><td>nova-frontend 团队的 MicroPython 定制版（含 nova-server）</td></tr><tr><td>ESP32</td><td>乐鑫出的微控制器芯片（带 WiFi）</td></tr><tr><td>GPIO</td><td>ESP32 上的引脚，可接 LED / 传感器</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>读完这些，就可以看代码了：</p><ul><li><a href="/nova-server/guide/first-route">第一个 GET 路由</a> — 5 分钟跑通</li><li><a href="/nova-server/guide/getting-started">快速开始</a> — 烧录固件 + 部署</li></ul>`,54)])])}const g=t(e,[["render",p]]);export{c as __pageData,g as default};
